import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Validate input length before copying to buffer
        if (name.length() > 10) {
            System.out.println("Input too long. Please enter a name with 10 characters or less.");
            return;
        }

        char[] buffer = new char[10];
        name.getChars(0, Math.min(name.length(), 10), buffer, 0); // Copy up to 10 characters

        System.out.println("Welcome, " + String.valueOf(buffer).trim()); // Trim excess whitespace
    }
}

### Explanation:
취약유형: Buffer Overflow
